package registry

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

const SupportedPackageAPIVersion = "1"

// ValidationIssue represents one package or plugin validation problem.
type ValidationIssue struct {
	Path    string
	Message string
}

func (i ValidationIssue) Error() string {
	if i.Path == "" {
		return i.Message
	}
	return fmt.Sprintf("%s: %s", i.Path, i.Message)
}

type packageManifestRaw struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        string         `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  any            `yaml:"api_version"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords"`
}

// knownManifestKeys is the set of top-level keys consumed by the current
// manifest schema. Any additional keys are preserved on Package.Extra so
// manifests written against newer api_versions round-trip without silent
// field loss.
var knownManifestKeys = map[string]struct{}{
	"name":        {},
	"version":     {},
	"description": {},
	"type":        {},
	"source":      {},
	"api_version": {},
	"install":     {},
	"keywords":    {},
}

// LoadPackageManifest reads and validates package.yaml from root.
func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
	manifestPath := filepath.Join(root, "package.yaml")
	data, err := os.ReadFile(manifestPath)
	if err != nil {
		return nil, nil, err
	}

	var raw packageManifestRaw
	if err := yaml.Unmarshal(data, &raw); err != nil {
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	// Also unmarshal into a free-form map so any keys not in the typed
	// struct survive as Package.Extra. yaml.v3 returns
	// map[string]any, preserving nested structure for round-trip.
	var full map[string]any
	if err := yaml.Unmarshal(data, &full); err != nil {
		// If the typed unmarshal succeeded, this cannot realistically
		// fail — but guard anyway.
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	pkg, issues := validatePackageManifest(manifestPath, raw)
	if pkg != nil {
		if extra := extraManifestKeys(full); len(extra) > 0 {
			pkg.Extra = extra
		}
	}
	if len(issues) > 0 && pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	// Even when validation issues exist, return the partial package so callers
	// can perform structural audits (symlinks, SKILL.md files) independently.
	// However, if no package was returned at all, return an error so callers
	// know something is fundamentally wrong.
	if pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	return pkg, issues, nil
}

// extraManifestKeys returns manifest keys that are not part of the current
// typed schema. Values are preserved as-is so callers can inspect them later.
func extraManifestKeys(full map[string]any) map[string]any {
	if len(full) == 0 {
		return nil
	}
	var extra map[string]any
	for k, v := range full {
		if _, known := knownManifestKeys[k]; known {
			continue
		}
		if extra == nil {
			extra = make(map[string]any, len(full))
		}
		extra[k] = v
	}
	return extra
}

// LoadPackageManifestWithFallback reads package.yaml and falls back to the
// provided package when the manifest is missing.
func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
	pkg, issues, err := LoadPackageManifest(root)
	if err == nil {
		// Return issues separately even when package is valid, so callers can
		// detect schema problems while still using the package for structural audits.
		if len(issues) > 0 {
			return pkg, false, issues, nil
		}
		return pkg, false, nil, nil
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so callers can still use its structure.
	if pkg != nil {
		return pkg, false, issues, nil
	}

	if os.IsNotExist(err) {
		return fallback, true, nil, err
	}

	if fallback != nil {
		return fallback, false, issues, err
	}
	return nil, false, issues, err
}

// validatePackageManifest validates required fields and returns a partial package
// even when validation issues are found. This ensures that structural audits
// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
	var issues []ValidationIssue

	name := strings.TrimSpace(raw.Name)
	if name == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
	}
	version := strings.TrimSpace(raw.Version)
	if version == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
	}
	description := strings.TrimSpace(raw.Description)
	if description == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
	}
	pkgType, ok := parseManifestPackageType(raw.Type)
	if !ok {
		issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
	}
	source := strings.TrimSpace(raw.Source)
	if source == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
	}

	apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
	if apiIssue != "" {
		issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
	}

	// Always construct a partial package so structural audits can proceed.
	// Validation issues are still collected and returned separately.
	pkg := &Package{
		Name:        name,
		Version:     version,
		Description: description,
		Type:        pkgType,
		Source:      source,
		APIVersion:  apiVersion,
		Install:     raw.Install,
		Keywords:    append([]string(nil), raw.Keywords...),
	}
	return pkg, issues
}

func parseManifestPackageType(rawType string) (PackageType, bool) {
	switch PackageType(strings.TrimSpace(rawType)) {
	case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
		return PackageType(strings.TrimSpace(rawType)), true
	default:
		return "", false
	}
}

func parseAPIVersion(raw any) (string, string) {
	if raw == nil {
		return "", "missing required field `api_version`"
	}

	value := strings.TrimSpace(fmt.Sprint(raw))
	if value == "" {
		return "", "missing required field `api_version`"
	}
	if value != SupportedPackageAPIVersion {
		return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
	}
	return value, ""
}

// Package perf provides a reusable GraphQL performance harness for the DDx
// server. It seeds realistic on-disk fixtures (projects × beads, docgraph,
// agent sessions) using the real storage primitives, then drives each GraphQL
// query shape through both the in-process StateProvider and the full HTTP
// handler while recording p50/p95/p99 latencies.
//
// The harness exists so performance work can be grounded in numbers rather
// than anecdote (ddx-9ce6842a Part 1). New query shapes are added by
// appending to the target table in harness.go — the fixture and measurement
// layers stay unchanged.
package perf

import (
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"runtime"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/server"
)

// BeadFixtureSpec describes the shape of a generated workspace.
//
// The defaults (10 projects × 500 beads = 5,000 beads) match the ddx-9ce6842a
// acceptance criteria §5, and the per-query floor of ≥1,000 records documented
// in the 2026-04-22 user directive on fixture size. Consumers that want a
// heavier run should raise BeadsPerProject rather than Projects so the
// distribution stays comparable.
type BeadFixtureSpec struct {
	// Projects is the number of registered projects. Must be ≥ 1.
	Projects int
	// BeadsPerProject is the number of beads seeded in each project.
	// Combined with Projects this yields the total bead corpus size.
	BeadsPerProject int
	// ClosedRatio (0..1) controls the fraction of seeded beads written with
	// status=closed. Defaults to 0.3. A realistic mix matters because
	// status=open filters are the common fast-path.
	ClosedRatio float64
	// LabelDensity is the number of labels assigned per bead. Defaults to 2.
	LabelDensity int
	// AgentSessionsPerProject is the number of agent-session rows seeded into
	// each project's sessions.jsonl file. 0 means "do not seed sessions" —
	// the sessions harness target will still run but report against the
	// naturally-empty feed.
	AgentSessionsPerProject int
	// DocGraphFilesPerProject is the number of stub markdown files seeded
	// into each project so the DocGraph target exercises real IO. 0 means
	// the harness uses only whatever files already exist under the server's
	// working directory.
	DocGraphFilesPerProject int
}

// DefaultBeadFixtureSpec is the baseline fixture: 10 projects × 500 beads
// (5,000 total) with a modest amount of docgraph + sessions content. This is
// what `make bench-graphql` runs and what baseline reports compare against.
func DefaultBeadFixtureSpec() BeadFixtureSpec {
	return BeadFixtureSpec{
		Projects:                10,
		BeadsPerProject:         500,
		ClosedRatio:             0.3,
		LabelDensity:            2,
		AgentSessionsPerProject: 100, // 10 × 100 = 1,000 session rows
		DocGraphFilesPerProject: 4,
	}
}

// BeadFixture is a materialised on-disk workspace plus a live server.Server
// bound to it. Callers drive queries through Handler / State.
type BeadFixture struct {
	Spec          BeadFixtureSpec
	Server        *server.Server
	Handler       http.Handler
	Projects      []server.ProjectEntry
	TargetProject server.ProjectEntry
	TargetBeadID  string
	BeadIDsByProj map[string][]string
}

// TotalBeads returns the aggregate bead count across all seeded projects.
func (f *BeadFixture) TotalBeads() int {
	return f.Spec.Projects * f.Spec.BeadsPerProject
}

// BuildBeadFixture seeds the described workspace and returns a live fixture.
// It registers every project with the server's state so cross-project queries
// see all of them. The fixture is torn down automatically via tb.Cleanup.
func BuildBeadFixture(tb testing.TB, spec BeadFixtureSpec) *BeadFixture {
	tb.Helper()
	if spec.Projects < 1 {
		tb.Fatalf("perf: fixture needs at least 1 project, got %d", spec.Projects)
	}
	if spec.BeadsPerProject < 1 {
		tb.Fatalf("perf: fixture needs at least 1 bead per project, got %d", spec.BeadsPerProject)
	}
	if spec.LabelDensity <= 0 {
		spec.LabelDensity = 1
	}
	if spec.ClosedRatio < 0 {
		spec.ClosedRatio = 0
	}
	if spec.ClosedRatio > 1 {
		spec.ClosedRatio = 1
	}

	// Keep state out of the real user XDG dir so tests are hermetic.
	tb.Setenv("XDG_DATA_HOME", tb.TempDir())
	tb.Setenv("DDX_NODE_NAME", "ddx-perf-harness")

	root := tb.TempDir()
	projectPaths := make([]string, 0, spec.Projects)
	beadIDsByProj := make(map[string][]string, spec.Projects)
	var targetBeadID string

	for pi := 0; pi < spec.Projects; pi++ {
		projectPath := filepath.Join(root, fmt.Sprintf("project-%02d", pi))
		beads := seedProjectBeads(tb, projectPath, pi, spec)
		ids := make([]string, len(beads))
		for i, b := range beads {
			ids[i] = b.ID
		}
		beadIDsByProj[projectPath] = ids
		if spec.DocGraphFilesPerProject > 0 {
			seedProjectDocGraph(tb, projectPath, pi, spec.DocGraphFilesPerProject)
		}
		if spec.AgentSessionsPerProject > 0 {
			seedProjectSessions(tb, projectPath, pi, spec.AgentSessionsPerProject)
		}
		projectPaths = append(projectPaths, projectPath)
		if pi == spec.Projects-1 && len(beads) > 0 {
			// Target the final project's final bead so GetBeadSnapshot must
			// walk past the other (spec.Projects - 1) projects on the slow
			// path — this is what ddx-ad0db8fd cared about.
			targetBeadID = beads[len(beads)-1].ID
		}
	}

	srv := server.New(":0", projectPaths[0])
	tb.Cleanup(func() { _ = srv.Shutdown() })
	for _, p := range projectPaths[1:] {
		srv.RegisterProject(p)
	}

	projects := srv.State().GetProjects()
	if len(projects) != spec.Projects {
		tb.Fatalf("perf: registered %d projects, expected %d", len(projects), spec.Projects)
	}
	var targetProject server.ProjectEntry
	for _, proj := range projects {
		if proj.Path == projectPaths[len(projectPaths)-1] {
			targetProject = proj
			break
		}
	}
	if targetProject.ID == "" {
		tb.Fatalf("perf: target project was not registered")
	}

	return &BeadFixture{
		Spec:          spec,
		Server:        srv,
		Handler:       srv.Handler(),
		Projects:      projects,
		TargetProject: targetProject,
		TargetBeadID:  targetBeadID,
		BeadIDsByProj: beadIDsByProj,
	}
}

func seedProjectBeads(tb testing.TB, projectPath string, projectIdx int, spec BeadFixtureSpec) []bead.Bead {
	tb.Helper()
	store := bead.NewStore(filepath.Join(projectPath, ".ddx"))
	if err := store.Init(); err != nil {
		tb.Fatalf("perf: init bead store: %v", err)
	}
	baseTime := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	beads := make([]bead.Bead, 0, spec.BeadsPerProject)
	closedCutoff := int(float64(spec.BeadsPerProject) * spec.ClosedRatio)
	for bi := 0; bi < spec.BeadsPerProject; bi++ {
		id := fmt.Sprintf("ddx-perf-%02d-%04d", projectIdx, bi)
		now := baseTime.Add(time.Duration(projectIdx*spec.BeadsPerProject+bi) * time.Second)
		status := bead.StatusOpen
		if bi < closedCutoff {
			status = bead.StatusClosed
		}
		labels := make([]string, 0, spec.LabelDensity)
		for li := 0; li < spec.LabelDensity; li++ {
			labels = append(labels, fmt.Sprintf("label-%d", (bi+li)%7))
		}
		labels = append(labels, fmt.Sprintf("project-%02d", projectIdx))
		beads = append(beads, bead.Bead{
			ID:          id,
			Title:       fmt.Sprintf("Perf fixture bead %02d/%04d", projectIdx, bi),
			Status:      status,
			Priority:    bead.DefaultPriority,
			IssueType:   bead.DefaultType,
			CreatedAt:   now,
			UpdatedAt:   now,
			Labels:      labels,
			Description: "GraphQL perf fixture — realistic-shape bead with a multi-line description so parsing costs reflect typical payloads rather than artificially small bodies.",
		})
	}
	if err := store.WriteAll(beads); err != nil {
		tb.Fatalf("perf: seed bead store: %v", err)
	}
	return beads
}

func seedProjectDocGraph(tb testing.TB, projectPath string, projectIdx, count int) {
	tb.Helper()
	docsDir := filepath.Join(projectPath, "docs", "helix", "01-frame", "features")
	if err := os.MkdirAll(docsDir, 0o755); err != nil {
		tb.Fatalf("perf: mkdir docgraph: %v", err)
	}
	for di := 0; di < count; di++ {
		name := fmt.Sprintf("FEAT-%02d-%03d.md", projectIdx, di)
		path := filepath.Join(docsDir, name)
		body := fmt.Sprintf("---\nid: FEAT-%02d-%03d\ntitle: Perf fixture feature\n---\n\n# FEAT-%02d-%03d\n\nFixture body line 1\nFixture body line 2\n", projectIdx, di, projectIdx, di)
		if err := os.WriteFile(path, []byte(body), 0o644); err != nil {
			tb.Fatalf("perf: write docgraph file: %v", err)
		}
	}
}

func seedProjectSessions(tb testing.TB, projectPath string, projectIdx, count int) {
	tb.Helper()
	logDir := agent.SessionLogDirForWorkDir(projectPath)
	base := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	for si := 0; si < count; si++ {
		started := base.Add(time.Duration(projectIdx*count+si) * time.Minute)
		entry := agent.SessionIndexEntry{
			ID:         fmt.Sprintf("sess-%02d-%05d", projectIdx, si),
			ProjectID:  agent.ProjectIDForPath(projectPath),
			BeadID:     fmt.Sprintf("ddx-perf-%02d-%04d", projectIdx, si%10),
			Harness:    "claude",
			Surface:    "execute-bead",
			Model:      "claude-sonnet-4-6",
			StartedAt:  started,
			EndedAt:    started.Add(time.Duration(1000+si*10) * time.Millisecond),
			DurationMS: 1000 + si*10,
			Tokens:     1000 + si,
			Outcome:    "success",
			Effort:     "medium",
		}
		if err := agent.AppendSessionIndex(logDir, entry, started); err != nil {
			tb.Fatalf("perf: write session index row: %v", err)
		}
	}
}

// Environment returns a short footer describing the machine the benchmark ran
// on. Included verbatim in the baseline report (ddx-9ce6842a AC §2).
func Environment() string {
	return fmt.Sprintf("go=%s goos=%s goarch=%s cpu-cores=%d", runtime.Version(), runtime.GOOS, runtime.GOARCH, runtime.NumCPU())
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// artifactTestGitOps is a GitOps mock for artifact-focused tests. It lets
// each test control the base/result revisions and populate the worktree.
type artifactTestGitOps struct {
	projectRoot string
	baseRev     string
	resultRev   string
	wtSetupFn   func(wtPath string)
}

func (m *artifactTestGitOps) HeadRev(dir string) (string, error) {
	if filepath.Clean(dir) == filepath.Clean(m.projectRoot) {
		return m.baseRev, nil
	}
	return m.resultRev, nil
}
func (m *artifactTestGitOps) ResolveRev(dir, rev string) (string, error) { return m.baseRev, nil }
func (m *artifactTestGitOps) WorktreeAdd(dir, wtPath, rev string) error {
	if err := os.MkdirAll(wtPath, 0o755); err != nil {
		return err
	}
	if m.wtSetupFn != nil {
		m.wtSetupFn(wtPath)
	}
	return nil
}
func (m *artifactTestGitOps) WorktreeRemove(dir, wtPath string) error { return nil }
func (m *artifactTestGitOps) WorktreeList(dir string) ([]string, error) {
	return nil, nil
}
func (m *artifactTestGitOps) WorktreePrune(dir string) error                 { return nil }
func (m *artifactTestGitOps) IsDirty(dir string) (bool, error)               { return false, nil }
func (m *artifactTestGitOps) SynthesizeCommit(dir, msg string) (bool, error) { return false, nil }
func (m *artifactTestGitOps) UpdateRef(dir, ref, sha string) error           { return nil }
func (m *artifactTestGitOps) DeleteRef(dir, ref string) error                { return nil }

// artifactTestAgentRunner returns a fixed Result for artifact tests.
type artifactTestAgentRunner struct {
	result *Result
}

func (r *artifactTestAgentRunner) Run(opts RunArgs) (*Result, error) {
	if r.result != nil {
		return r.result, nil
	}
	return &Result{ExitCode: 0}, nil
}

// setupArtifactTestProjectRoot creates a minimal projectRoot with .ddx/.
func setupArtifactTestProjectRoot(t *testing.T) string {
	t.Helper()
	root := t.TempDir()
	if err := os.MkdirAll(filepath.Join(root, ".ddx"), 0o755); err != nil {
		t.Fatal(err)
	}
	return root
}

// setupArtifactTestWorktree populates wtPath with a bead store containing one
// bead. Optionally includes a governing spec and a required gate.
func setupArtifactTestWorktree(t *testing.T, wtPath, beadID, specID string, withGate bool, gateExit int) {
	t.Helper()
	ddxDir := filepath.Join(wtPath, ".ddx")
	if err := os.MkdirAll(ddxDir, 0o755); err != nil {
		t.Fatal(err)
	}
	store := bead.NewStore(ddxDir)
	if err := store.Init(); err != nil {
		t.Fatal(err)
	}
	b := &bead.Bead{
		ID:    beadID,
		Title: "Artifact test bead",
	}
	if specID != "" {
		b.Extra = map[string]any{"spec-id": specID}
		writeArtifactDoc(t, wtPath, specID)
	}
	if err := store.Create(b); err != nil {
		t.Fatal(err)
	}
	if withGate {
		cmd := fmt.Sprintf("exit %d", gateExit)
		writeGateDoc(t, wtPath, "exec."+specID+".smoke", specID, true, []string{"sh", "-c", cmd})
	}
}

// TestArtifactBundle_Paths verifies that createArtifactBundle produces
// deterministic, correctly scoped relative paths for all six artifacts.
func TestArtifactBundle_Paths(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()
	const attemptID = "20260101T000000-aabbccdd"

	arts, err := createArtifactBundle(root, wt, attemptID)
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	wantDirRel := ".ddx/executions/" + attemptID
	if arts.DirRel != wantDirRel {
		t.Errorf("DirRel = %q, want %q", arts.DirRel, wantDirRel)
	}
	cases := []struct{ name, rel, abs string }{
		{"prompt", arts.PromptRel, arts.PromptAbs},
		{"manifest", arts.ManifestRel, arts.ManifestAbs},
		{"result", arts.ResultRel, arts.ResultAbs},
		{"checks", arts.ChecksRel, arts.ChecksAbs},
		{"usage", arts.UsageRel, arts.UsageAbs},
	}
	for _, c := range cases {
		wantRel := wantDirRel + "/" + filepath.Base(c.abs)
		if c.rel != wantRel {
			t.Errorf("%s rel = %q, want %q", c.name, c.rel, wantRel)
		}
		if filepath.Dir(c.abs) != arts.DirAbs {
			t.Errorf("%s abs dir = %q, want %q", c.name, filepath.Dir(c.abs), arts.DirAbs)
		}
	}

	// Directory must exist after createArtifactBundle.
	if fi, err := os.Stat(arts.DirAbs); err != nil || !fi.IsDir() {
		t.Errorf("artifact directory %q not created: %v", arts.DirAbs, err)
	}
}

// TestExecuteBead_ArtifactsCreated verifies that a successful execute-bead
// run produces prompt.md, manifest.json, and result.json on disk.
func TestExecuteBead_ArtifactsCreated(t *testing.T) {
	const beadID = "ddx-art-01"

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "aaaa000000000001",
		resultRev:   "aaaa000000000001", // no-changes outcome
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})
	res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{AgentRunner: &artifactTestAgentRunner{}}, gitOps)
	if err != nil {
		t.Fatalf("ExecuteBead: %v", err)
	}

	bundleDir := filepath.Join(projectRoot, ".ddx", "executions", res.AttemptID)
	for _, name := range []string{"prompt.md", "manifest.json", "result.json"} {
		p := filepath.Join(bundleDir, name)
		if _, err := os.Stat(p); err != nil {
			t.Errorf("expected artifact %q to exist: %v", name, err)
		}
	}
}

// TestExecuteBead_ManifestShape verifies that manifest.json contains the
// required machine-readable fields and correct top-level structure.
func TestExecuteBead_ManifestShape(t *testing.T) {
	const beadID = "ddx-art-02"
	const specID = "FEAT-ARTTEST"

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "bbbb000000000001",
		resultRev:   "bbbb000000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, specID, false, 0)
		},
	}

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{
		Harness: "test-harness",
		Model:   "test-model",
	}).Resolve(config.CLIOverrides{})
	res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
		AgentRunner: &artifactTestAgentRunner{},
	}, gitOps)
	if err != nil {
		t.Fatalf("ExecuteBead: %v", err)
	}

	manifestPath := filepath.Join(projectRoot, ".ddx", "executions", res.AttemptID, "manifest.json")
	raw, err := os.ReadFile(manifestPath)
	if err != nil {
		t.Fatalf("reading manifest.json: %v", err)
	}

	var m struct {
		AttemptID string `json:"attempt_id"`
		BeadID    string `json:"bead_id"`
		BaseRev   string `json:"base_rev"`
		CreatedAt string `json:"created_at"`
		Requested struct {
			Harness string `json:"harness"`
			Model   string `json:"model"`
			Prompt  string `json:"prompt"`
		} `json:"requested"`
		Bead struct {
			ID    string `json:"id"`
			Title string `json:"title"`
		} `json:"bead"`
		Governing []struct {
			ID   string `json:"id"`
			Path string `json:"path"`
		} `json:"governing"`
		Paths struct {
			Dir      string `json:"dir"`
			Prompt   string `json:"prompt"`
			Manifest string `json:"manifest"`
			Result   string `json:"result"`
			Checks   string `json:"checks"`
			Usage    string `json:"usage"`
			Worktree string `json:"worktree"`
		} `json:"paths"`
		PromptSHA string `json:"prompt_sha"`
	}
	if err := json.Unmarshal(raw, &m); err != nil {
		t.Fatalf("parsing manifest.json: %v", err)
	}

	if m.AttemptID == "" {
		t.Error("manifest.attempt_id must not be empty")
	}
	if m.BeadID != beadID {
		t.Errorf("manifest.bead_id = %q, want %q", m.BeadID, beadID)
	}
	if m.BaseRev != "bbbb000000000001" {
		t.Errorf("manifest.base_rev = %q, want %q", m.BaseRev, "bbbb000000000001")
	}
	if m.CreatedAt == "" {
		t.Error("manifest.created_at must not be empty")
	}
	if m.Requested.Harness != "test-harness" {
		t.Errorf("manifest.requested.harness = %q, want %q", m.Requested.Harness, "test-harness")
	}
	if m.Requested.Model != "test-model" {
		t.Errorf("manifest.requested.model = %q, want %q", m.Requested.Model, "test-model")
	}
	if m.Requested.Prompt != "synthesized" {
		t.Errorf("manifest.requested.prompt = %q, want %q", m.Requested.Prompt, "synthesized")
	}
	if m.Bead.ID != beadID {
		t.Errorf("manifest.bead.id = %q, want %q", m.Bead.ID, beadID)
	}

